parameters.text:
You are a career roadmap planner.

CONTEXT
Gap analysis:
{{ $('Gap Analysis').item.json.output }}

Certification recommendations:
{{ $json.output }}

TASK
1. Choose the single best-fit target career from the gap analysis.
2. Build a phased roadmap with exactly 3 phases: "0-3 Months", "3-6 Months", "6-12 Months".
3. For each phase, define: goals, certifications (from the recommended list that fit this phase), and milestones.
4. Write a short overall summary (2-3 sentences).

OUTPUT FORMAT
Return valid JSON only. No markdown code fences, no explanation text before or after the JSON.

{
  "career_roadmap": {
    "target_career": "...",
    "phases": [
      { "phase": "0-3 Months", "goals": ["..."], "certifications": ["..."], "milestones": ["..."] }
    ],
    "summary": "..."
  }
}

LANGUAGE RULE
- JSON keys must stay in English exactly as shown.
- All text VALUES must be written in Bahasa Indonesia.

parameters.jsCode:
function safeParse(raw, fallback) {
  try {
    const cleaned = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
    return JSON.parse(cleaned);
  } catch (e) { return fallback; }
}

const careerPathsRaw = safeParse($('Career Path Classification').first().json.output, { career_paths: [] });
const gapRaw = safeParse($('Gap Analysis').first().json.output, { careers: [] });
const certRaw = safeParse($('Recommend Certification').first().json.output, { recommendations: [] });
const roadmapRaw = safeParse($input.first().json.output, { career_roadmap: {} });

return [{
  json: {
    career_paths: careerPathsRaw.career_paths || [],
    gap_analysis: gapRaw.careers || [],
    certifications: certRaw.recommendations || [],
    career_roadmap: roadmapRaw.career_roadmap || {},
  }
}];
